import{_ as a,c as s,o as e,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Usage: Query AI Quota | opencode-mystatus","description":"Learn how to use opencode-mystatus to query AI quotas. Supports slash commands and natural language queries for OpenAI, Zhipu AI, Z.ai, GitHub Copilot, and Google Cloud with real-time progress bars.","frontmatter":{"title":"Usage: Query AI Quota | opencode-mystatus","sidebarTitle":"Usage","subtitle":"Using mystatus: Slash Commands and Natural Language","description":"Learn how to use opencode-mystatus to query AI quotas. Supports slash commands and natural language queries for OpenAI, Zhipu AI, Z.ai, GitHub Copilot, and Google Cloud with real-time progress bars.","tags":["Quick Start","Slash Commands","Natural Language"],"prerequisite":["start-quick-start"],"order":999},"headers":[],"relativePath":"vbgate/opencode-mystatus/start/using-mystatus/index.md","filePath":"vbgate/opencode-mystatus/start/using-mystatus/index.md"}'),n={name:"vbgate/opencode-mystatus/start/using-mystatus/index.md"};function i(l,t,r,u,d,p){return e(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="using-mystatus-slash-commands-and-natural-language" tabindex="-1">Using mystatus: Slash Commands and Natural Language <a class="header-anchor" href="#using-mystatus-slash-commands-and-natural-language" aria-label="Permalink to &quot;Using mystatus: Slash Commands and Natural Language&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Use the <code>/mystatus</code> slash command to query all AI platform quotas in one click</li><li>Use natural language queries to let OpenCode automatically invoke the mystatus tool</li><li>Understand the differences and use cases for slash commands vs natural language</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You&#39;re developing with multiple AI platforms (OpenAI, Zhipu AI, GitHub Copilot, etc.) and want to know how much quota you have left on each platform, but logging into each platform individually to check is too cumbersome.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li><strong>When you need a quick overview of all platform quotas</strong>: Check before daily development to plan usage wisely</li><li><strong>When you want to check a specific platform&#39;s quota</strong>: For example, confirming if OpenAI is running low</li><li><strong>When verifying configuration</strong>: After setting up a new account, confirm it can be queried correctly</li></ul><div class="info custom-block"><p class="custom-block-title">Prerequisites</p><p>This tutorial assumes you have completed the <a href="/docs/opencodedocs/vbgate/opencode-mystatus/start/quick-start/">opencode-mystatus plugin installation</a>. If not, please complete the installation steps first.</p></div><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>opencode-mystatus provides two ways to trigger the mystatus tool:</p><ol><li><strong>Slash command <code>/mystatus</code></strong>: Fast, direct, unambiguous—ideal for frequent queries</li><li><strong>Natural language queries</strong>: More flexible—suited for context-specific queries</li></ol><p>Both methods invoke the same <code>mystatus</code> tool, which queries all configured AI platforms in parallel and returns results with progress bars, usage statistics, and reset countdowns.</p><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-query-quota-using-slash-command" tabindex="-1">Step 1: Query Quota Using Slash Command <a class="header-anchor" href="#step-1-query-quota-using-slash-command" aria-label="Permalink to &quot;Step 1: Query Quota Using Slash Command&quot;">​</a></h3><p>Enter the following command in OpenCode:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/mystatus</span></span></code></pre></div><p><strong>Why</strong> Slash commands are OpenCode&#39;s shortcut mechanism for quickly invoking predefined tools. The <code>/mystatus</code> command directly invokes the mystatus tool with no additional parameters required.</p><p><strong>You should see</strong>: OpenCode returns quota information for all configured platforms, formatted as follows:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (team)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████████████████ 85% remaining</span></span>
<span class="line"><span>Reset: 2h 30m</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## Zhipu AI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        9c89****AQVM (Coding Plan)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5-hour token limit</span></span>
<span class="line"><span>███████████████████████████ 95% remaining</span></span>
<span class="line"><span>Used: 0.5M / 10.0M</span></span>
<span class="line"><span>Reset: 4h</span></span></code></pre></div><p>Each platform displays:</p><ul><li>Account information (email or masked API key)</li><li>Progress bar (visualizing remaining quota)</li><li>Reset countdown</li><li>Used and total usage (for some platforms)</li></ul><h3 id="step-2-query-using-natural-language" tabindex="-1">Step 2: Query Using Natural Language <a class="header-anchor" href="#step-2-query-using-natural-language" aria-label="Permalink to &quot;Step 2: Query Using Natural Language&quot;">​</a></h3><p>Besides slash commands, you can also use natural language to ask questions. OpenCode will automatically recognize your intent and invoke the mystatus tool.</p><p>Try these query formats:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Check</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OpenAI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span></span></code></pre></div><p>Or</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">How</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> much</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Codex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> quota</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> do</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> have</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> left?</span></span></code></pre></div><p>Or</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AI</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> account</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span></code></pre></div><p><strong>Why</strong> Natural language queries feel more like everyday conversation and fit naturally into specific development contexts. OpenCode uses semantic matching to identify that you want to check quota and automatically invokes the mystatus tool.</p><p><strong>You should see</strong>: The same output as the slash command—just a different trigger method.</p><h3 id="step-3-understand-slash-command-configuration" tabindex="-1">Step 3: Understand Slash Command Configuration <a class="header-anchor" href="#step-3-understand-slash-command-configuration" aria-label="Permalink to &quot;Step 3: Understand Slash Command Configuration&quot;">​</a></h3><p>How does the slash command <code>/mystatus</code> work? It&#39;s defined in your OpenCode configuration file.</p><p>Open <code>~/.config/opencode/opencode.json</code> and find the <code>command</code> section:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;opencode-mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;command&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;mystatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Query quota usage for all AI accounts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;template&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Use the mystatus tool to query quota usage. Return the result as-is without modification.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Key Configuration Explained</strong>:</p><table tabindex="0"><thead><tr><th>Config</th><th>Value</th><th>Purpose</th></tr></thead><tbody><tr><td><code>description</code></td><td>&quot;Query quota usage for all AI accounts&quot;</td><td>Description shown in the command list</td></tr><tr><td><code>template</code></td><td>&quot;Use the mystatus tool...&quot;</td><td>Instructs OpenCode how to handle this command</td></tr></tbody></table><p><strong>Why template is needed</strong> The template is an &quot;instruction&quot; for OpenCode, telling it: when the user inputs <code>/mystatus</code>, invoke the mystatus tool and return the result as-is without any modifications.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>Confirm you&#39;ve mastered both usage methods:</p><table tabindex="0"><thead><tr><th>Skill</th><th>How to Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Slash command query</td><td>Input <code>/mystatus</code></td><td>Displays quota information for all platforms</td></tr><tr><td>Natural language query</td><td>Input &quot;Check my OpenAI quota&quot;</td><td>Displays quota information</td></tr><tr><td>Understand configuration</td><td>View opencode.json</td><td>Find the mystatus command configuration</td></tr></tbody></table><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="common-error-1-slash-command-no-response" tabindex="-1">Common Error 1: Slash Command No Response <a class="header-anchor" href="#common-error-1-slash-command-no-response" aria-label="Permalink to &quot;Common Error 1: Slash Command No Response&quot;">​</a></h3><p><strong>Symptom</strong>: No response after entering <code>/mystatus</code></p><p><strong>Cause</strong>: OpenCode configuration file doesn&#39;t have the slash command properly configured</p><p><strong>Solution</strong>:</p><ol><li>Open <code>~/.config/opencode/opencode.json</code></li><li>Confirm the <code>command</code> section includes <code>mystatus</code> configuration (see Step 3)</li><li>Restart OpenCode</li></ol><h3 id="common-error-2-natural-language-query-doesn-t-invoke-mystatus-tool" tabindex="-1">Common Error 2: Natural Language Query Doesn&#39;t Invoke mystatus Tool <a class="header-anchor" href="#common-error-2-natural-language-query-doesn-t-invoke-mystatus-tool" aria-label="Permalink to &quot;Common Error 2: Natural Language Query Doesn&#39;t Invoke mystatus Tool&quot;">​</a></h3><p><strong>Symptom</strong>: After entering &quot;Check my OpenAI quota&quot;, OpenCode doesn&#39;t invoke the mystatus tool and tries to answer itself</p><p><strong>Cause</strong>: OpenCode didn&#39;t correctly recognize your intent</p><p><strong>Solution</strong>:</p><ol><li>Try a more explicit phrasing: &quot;Use mystatus tool to check my OpenAI quota&quot;</li><li>Or use the slash command <code>/mystatus</code> directly—more reliable</li></ol><h3 id="common-error-3-shows-no-configured-accounts-found" tabindex="-1">Common Error 3: Shows &quot;No Configured Accounts Found&quot; <a class="header-anchor" href="#common-error-3-shows-no-configured-accounts-found" aria-label="Permalink to &quot;Common Error 3: Shows &quot;No Configured Accounts Found&quot;&quot;">​</a></h3><p><strong>Symptom</strong>: After executing <code>/mystatus</code>, displays &quot;No configured accounts found&quot;</p><p><strong>Cause</strong>: No platform authentication information has been configured</p><p><strong>Solution</strong>:</p><ul><li>Configure at least one platform&#39;s authentication (OpenAI, Zhipu AI, Z.ai, GitHub Copilot, or Google Cloud)</li><li>See the configuration instructions in the <a href="/docs/opencodedocs/vbgate/opencode-mystatus/start/quick-start/">Quick Start tutorial</a></li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The mystatus tool provides two usage methods:</p><ol><li><strong>Slash command <code>/mystatus</code></strong>: Fast and direct—ideal for frequent queries</li><li><strong>Natural language queries</strong>: More flexible—suited for specific contexts</li></ol><p>Both methods query all configured AI platforms in parallel and return results with progress bars and reset countdowns. The slash command is defined in <code>~/.config/opencode/opencode.json</code> and uses the template to instruct OpenCode how to invoke the mystatus tool.</p><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="/docs/opencodedocs/vbgate/opencode-mystatus/start/understanding-output/">Understanding Output: Progress Bars, Reset Times, and Multiple Accounts</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to interpret progress bar meanings</li><li>How reset countdowns are calculated</li><li>Output format in multi-account scenarios</li><li>Progress bar generation principles</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>mystatus tool definition</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>29-33</td></tr><tr><td>Tool description</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>30-31</td></tr><tr><td>Slash command configuration</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/command/mystatus.md" target="_blank" rel="noreferrer"><code>command/mystatus.md</code></a></td><td>1-6</td></tr><tr><td>Parallel query all platforms</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>49-56</td></tr><tr><td>Result collection and aggregation</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/mystatus.ts" target="_blank" rel="noreferrer"><code>plugin/mystatus.ts</code></a></td><td>58-89</td></tr></tbody></table><p><strong>Key Constants</strong>: None (this section mainly covers invocation methods, not specific constants)</p><p><strong>Key Functions</strong>:</p><ul><li><code>mystatus()</code>: Main function of the mystatus tool, reads auth files and queries all platforms in parallel (<code>plugin/mystatus.ts:29-33</code>)</li><li><code>collectResult()</code>: Collects query results into results and errors arrays (<code>plugin/mystatus.ts:100-116</code>)</li></ul></details>`,66)])])}const m=a(n,[["render",i]]);export{h as __pageData,m as default};
